          lineHeight: '1.6',
          color: 'var(--text-main)',
          whiteSpace: 'pre-wrap',
          wordBreak: 'break-word'
        }}>
          {message.content}
        </div>

        <span style={{ fontSize: '0.7rem', color: 'var(--text-dark)' }}>
