        {!isUser && message.tools && message.tools.length > 0 && (
          <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', marginBottom: '4px' }}>
            {message.tools.map((t, i) => (
              <span key={i} style={{
                fontSize: '0.65rem', padding: '2px 7px', borderRadius: '10px',
