          color: 'var(--text-main)',
          whiteSpace: 'pre-wrap',
          wordBreak: 'break-word'
        }}>
          {message.content}
        </div>

        <span style={{ fontSize: '0.7rem', color: 'var(--text-dark)' }}>
          {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
