            ? '1px solid rgba(0,242,254,0.2)'
            : '1px solid var(--card-border)',
          borderRadius: isUser ? '18px 18px 4px 18px' : '18px 18px 18px 4px',
          padding: '12px 16px',
          backdropFilter: 'blur(12px)',
